45	
46		-- TB Control
47		signal TbRunning 	: boolean 	:= true;
48		signal PrintIrq_c	: boolean	:= PrintDefault_c;
49	
50		-- Constants
51		constant StrCount_c	: integer	:= 4;
52		constant ClkFreq_c	: t_areal	:= (0=>250.0e6,	1=>125.0e6,	2=>80.0e6,	3=>200.0e6);
53		
54		-- Axi Memory
55		constant ID_WIDTH 		: integer 	:= 1;
56		constant ADDR_WIDTH 	: integer	:= 32;
57		constant USER_WIDTH		: integer	:= 1;
58		constant DATA_WIDTH		: integer	:= 128;
59		constant BYTE_WIDTH		: integer	:= DATA_WIDTH/8;
60		
61		constant IntDataWidth_g : integer := 128;
62	
63		subtype ID_RANGE is natural range ID_WIDTH-1 downto 0;
64		subtype ADDR_RANGE is natural range ADDR_WIDTH-1 downto 0;
65		subtype USER_RANGE is natural range USER_WIDTH-1 downto 0;
66		subtype DATA_RANGE is natural range DATA_WIDTH-1 downto 0;
67		subtype BYTE_RANGE is natural range BYTE_WIDTH-1 downto 0;
68		
69		subtype axi_ms_t is axi_ms_r (	arid(ID_RANGE), awid(ID_RANGE),
70										araddr(ADDR_RANGE), awaddr(ADDR_RANGE),
71										aruser(USER_RANGE), awuser(USER_RANGE), wuser(USER_RANGE),
72										wdata(DATA_RANGE),
73										wstrb(BYTE_RANGE));
74		
75		subtype axi_sm_t is axi_sm_r (	rid(ID_RANGE), bid(ID_RANGE),
76										ruser(USER_RANGE), buser(USER_RANGE),
77										rdata(DATA_RANGE));	
78	
79		-- Axi Registers
80		constant REG_ID_WIDTH 		: integer 	:= 1;
81		constant REG_ADDR_WIDTH 	: integer	:= 16;
82		constant REG_USER_WIDTH		: integer	:= 1;
83		constant REG_DATA_WIDTH		: integer	:= 32;
84		constant REG_BYTE_WIDTH		: integer	:= REG_DATA_WIDTH/8;
85		
86		subtype REG_ID_RANGE is natural range REG_ID_WIDTH-1 downto 0;
87		subtype REG_ADDR_RANGE is natural range REG_ADDR_WIDTH-1 downto 0;
88		subtype REG_USER_RANGE is natural range REG_USER_WIDTH-1 downto 0;
89		subtype REG_DATA_RANGE is natural range REG_DATA_WIDTH-1 downto 0;
90		subtype REG_BYTE_RANGE is natural range REG_BYTE_WIDTH-1 downto 0;
91		
92		subtype reg_axi_ms_t is axi_ms_r (	arid(REG_ID_RANGE), awid(REG_ID_RANGE),
93											araddr(REG_ADDR_RANGE), awaddr(REG_ADDR_RANGE),
94											aruser(REG_USER_RANGE), awuser(REG_USER_RANGE), wuser(REG_USER_RANGE),
95											wdata(REG_DATA_RANGE),
96											wstrb(REG_BYTE_RANGE));
97		
98		subtype reg_axi_sm_t is axi_sm_r (	rid(REG_ID_RANGE), bid(REG_ID_RANGE),
99											ruser(REG_USER_RANGE), buser(REG_USER_RANGE),
100											rdata(REG_DATA_RANGE));										
101		
102	
103		-- Port signals	
104		signal Str_Clk			: std_logic_vector(StrCount_c-1 downto 0)	:= (others => '0');
105		signal Str0_Data		: std_logic_vector(7 downto 0)				:= (others => '0');
106		signal Str1_Data		: std_logic_vector(15 downto 0)				:= (others => '0');
107		signal Str2_Data		: std_logic_vector(15 downto 0)				:= (others => '0');
108		signal Str3_Data		: std_logic_vector(31 downto 0)				:= (others => '0');
109		signal Timestamp		: t_aslv64(StrCount_c-1 downto 0)			:= (others => (others => '0'));
110		signal Str_Vld			: std_logic_vector(StrCount_c-1 downto 0)	:= (others => '0');
111		signal Str_Rdy			: std_logic_vector(StrCount_c-1 downto 0)	:= (others => '0');
112		signal Str_Trig			: std_logic_vector(StrCount_c-1 downto 0)	:= (others => '0');
113		signal M_Axi_Aclk		: std_logic									:= '0';
114		signal S_Axi_Aclk		: std_logic									:= '0';
115		signal M_Axi_Aresetn	: std_logic									:= '0';
116		signal S_Axi_Aresetn	: std_logic									:= '0';
117		signal Irq				: std_logic									:= '0';
118		signal axi_ms			: axi_ms_t;
119		signal axi_sm 			: axi_sm_t;
120		signal reg_axi_ms		: reg_axi_ms_t;
121		signal reg_axi_sm		: reg_axi_sm_t;
122		
123		
124		procedure IrqHandler(	signal	clk			: in	std_logic;
125								signal	rqst		: out 	axi_ms_r;
126								signal	rsp			: in	axi_sm_r) is
127			variable v : integer;
128			variable slv : std_logic_vector(31 downto 0);
129		begin
130			print("###################################### IRQ Detected #########################################", PrintIrq_c);
131			wait until rising_edge(clk);
132			AxiRead32(16#0010#, v, clk, rqst, rsp);
133			slv := std_logic_vector(to_unsigned(v, 32));
134			AxiWrite32(16#0010#, v, clk, rqst, rsp);
135			wait until rising_edge(clk);
136			for i in 0 to StrCount_c-1 loop
137				if slv(i) = '1' then
138					case i is 
139						when 0 => Str0Handler(clk, rqst, rsp);
140						when 1 => Str1Handler(clk, rqst, rsp);
141						when 2 => Str2Handler(clk, rqst, rsp);
142						when 3 => Str3Handler(clk, rqst, rsp);
143						when others => null;
144					end case;
145				end if;
146			end loop;
147			-- Delay to ensure IRQ is cleared
148			for i in 0 to 5 loop
149				wait until rising_edge(clk);
150			end loop;
151		end procedure;								
152								
153		
154	begin
155		------------------------------------------------------------
156		-- DUT Instantiation
157		------------------------------------------------------------
158		i_dut : entity work.psi_ms_daq_axi
159			generic map (
160				Streams_g				=> StrCount_c,
161				StreamWidth_g			=> (0=>8, 		1=>16, 			2=>16, 		3=>32),
162				StreamPrio_g			=> (0=>1, 		1=>3,  			2=>2,  		3=>2),
163				StreamBuffer_g			=> (0=>32, 		1=>128, 		2=>128, 	3=>128),
164				StreamTimeout_g			=> (0=>5.0e-6,	1=>1.0e-3,		2=>1.0e-3,	3=>1.0e-3),
165				StreamClkFreq_g			=> ClkFreq_c,
166				StreamTsFifoDepth_g		=> (0=>16,		1=>16,			2=>16,		3=>16),
167				StreamUseTs_g			=> (0=>true,	1=>true,		2=>true,	3=>false),
168				IntDataWidth_g			=> IntDataWidth_g,
169				MaxWindows_g			=> work.psi_ms_daq_axi_tb_pkg.MaxWindows_c,
170				MinBurstSize_g			=> 16,
171				MaxBurstSize_g			=> 128,
172				AxiDataWidth_g			=> DATA_WIDTH,
173				AxiFifoDepth_g			=> 512,
174				AxiSlaveIdWidth_g		=> 1
175			)
176			port map (
177				Str_Clk						=> Str_Clk,
178				Str_Data(0)(7 downto 0)		=> Str0_Data,
179				Str_Data(0)(63 downto 8)	=> (others => '0'),
180				Str_Data(1)(15 downto 0)	=> Str1_Data,
181				Str_Data(1)(63 downto 16)	=> (others => '0'),
182				Str_Data(2)(15 downto 0)	=> Str2_Data,
183				Str_Data(2)(63 downto 16)	=> (others => '0'),
184				Str_Data(3)(31 downto 0)	=> Str3_Data,
185				Str_Data(3)(63 downto 32)	=> (others => '0'),
186				Str_Ts						=> Timestamp,
187				Str_Vld						=> Str_Vld,
188				Str_Rdy						=> Str_Rdy,
189				Str_Trig					=> Str_Trig,
190				Irq							=> Irq,
191				S_Axi_Aclk					=> S_Axi_Aclk,
192				S_Axi_Aresetn				=> S_Axi_Aresetn,
193				S_Axi_ArId					=> reg_axi_ms.arid,
194				S_Axi_ArAddr				=> reg_axi_ms.araddr,
195				S_Axi_Arlen					=> reg_axi_ms.arlen,
196				S_Axi_ArSize				=> reg_axi_ms.arsize,
197				S_Axi_ArBurst				=> reg_axi_ms.arburst,
198				S_Axi_ArLock				=> reg_axi_ms.arlock,
199				S_Axi_ArCache				=> reg_axi_ms.arcache,
200				S_Axi_ArProt				=> reg_axi_ms.arprot, 
201				S_Axi_ArValid				=> reg_axi_ms.arvalid,
202				S_Axi_ArReady				=> reg_axi_sm.arready,
203				S_Axi_RId					=> reg_axi_sm.rid,
204				S_Axi_RData					=> reg_axi_sm.rdata,
205				S_Axi_RResp					=> reg_axi_sm.rresp,
206				S_Axi_RLast					=> reg_axi_sm.rlast,
207				S_Axi_RValid				=> reg_axi_sm.rvalid,
208				S_Axi_RReady				=> reg_axi_ms.rready,
209				S_Axi_AwAddr				=> reg_axi_ms.awaddr,
210				S_AXi_AwId					=> reg_axi_ms.awid,
211				S_Axi_AwLen					=> reg_axi_ms.awlen,
212				S_Axi_AwSize				=> reg_axi_ms.awsize,
213				S_Axi_AwBurst				=> reg_axi_ms.awburst,
214				S_Axi_AwLock				=> reg_axi_ms.awlock,
215				S_Axi_AwCache				=> reg_axi_ms.awcache,
216				S_Axi_AwProt				=> reg_axi_ms.awprot,
217				S_Axi_AwValid				=> reg_axi_ms.awvalid,
218				S_Axi_AwReady				=> reg_axi_sm.awready,
219				S_Axi_WData					=> reg_axi_ms.wdata,
220				S_Axi_WStrb					=> reg_axi_ms.wstrb,
221				S_Axi_WLast					=> reg_axi_ms.wlast,
222				S_Axi_WValid				=> reg_axi_ms.wvalid,
223				S_Axi_WReady				=> reg_axi_sm.wready,
224				S_Axi_BId					=> reg_axi_sm.bid,
225				S_Axi_BResp					=> reg_axi_sm.bresp,
226				S_Axi_BValid				=> reg_axi_sm.bvalid,
227				S_Axi_BReady				=> reg_axi_ms.bready,
228				M_Axi_Aclk					=> M_Axi_Aclk,
229				M_Axi_Aresetn				=> M_Axi_Aresetn,
230				M_Axi_AwAddr				=> axi_ms.awaddr,								
231				M_Axi_AwLen					=> axi_ms.awlen,
232				M_Axi_AwSize				=> axi_ms.awsize,
233				M_Axi_AwBurst				=> axi_ms.awburst,
234				M_Axi_AwLock				=> axi_ms.awlock,
235				M_Axi_AwCache				=> axi_ms.awcache,
236				M_Axi_AwProt				=> axi_ms.awprot,
237				M_Axi_AwValid				=> axi_ms.awvalid,
238				M_Axi_AwReady				=> axi_sm.awready,                             					
239				M_Axi_WData					=> axi_ms.wdata,
240				M_Axi_WStrb					=> axi_ms.wstrb,
241				M_Axi_WLast					=> axi_ms.wlast,
242				M_Axi_WValid				=> axi_ms.wvalid,
243				M_Axi_WReady				=> axi_sm.wready,                             
244				M_Axi_BResp					=> axi_sm.bresp,
245				M_Axi_BValid				=> axi_sm.bvalid,
246				M_Axi_BReady				=> axi_ms.bready,                    
247				M_Axi_ArAddr				=> axi_ms.araddr,
248				M_Axi_ArLen					=> axi_ms.arlen,
249				M_Axi_ArSize				=> axi_ms.arsize,
250				M_Axi_ArBurst				=> axi_ms.arburst,
251				M_Axi_ArLock				=> axi_ms.arlock,
252				M_Axi_ArCache				=> axi_ms.arcache,
253				M_Axi_ArProt				=> axi_ms.arprot,
254				M_Axi_ArValid				=> axi_ms.arvalid,
255				M_Axi_ArReady				=> axi_sm.arready,                          
256				M_Axi_RData					=> axi_sm.rdata,
257				M_Axi_RResp					=> axi_sm.rresp,
258				M_Axi_RLast					=> axi_sm.rlast,
259				M_Axi_RValid				=> axi_sm.rvalid,
260				M_Axi_RReady				=> axi_ms.rready
261			);
262			
263		------------------------------------------------------------
264		-- Emulate Memory
265		------------------------------------------------------------	
266		p_mem : process
267			variable Address_v		: integer;
268			variable Size_v			: integer;
269		begin
270			axi_slave_init(axi_sm);
271			wait until rising_edge(M_Axi_Aclk);
272			while TbRunning loop
273				axi_sm.awready <= '1';
274				wait until (rising_edge(M_Axi_Aclk) and axi_ms.awvalid = '1') or (not TbRunning);
275				if TbRunning then
276					axi_sm.awready <= '0';
277					axi_sm.wready <= '1';
278					Address_v	:= to_integer(unsigned(axi_ms.awaddr));
279					Size_v		:= to_integer(unsigned(axi_ms.awlen))+1;
280					for qw in 0 to Size_v-1 loop
281						wait until rising_edge(M_Axi_Aclk) and axi_ms.wvalid = '1';
282						for byte in 0 to 7 loop
283							if axi_ms.wstrb(byte) = '1' then
284								Memory(Address_v+qw*8+byte) <= axi_ms.wdata(byte*8+7 downto byte*8);
285							end if;
286						end loop;
287					end loop;
288					StdlCompare(1, axi_ms.wlast, "Last not received at end of burst");
289					axi_sm.wready <= '0';
290					axi_sm.bresp <= xRESP_OKAY_c;
291					axi_sm.bvalid <= '1';
292					wait until rising_edge(M_Axi_Aclk) and axi_ms.bready = '1';
293					axi_sm.bvalid <= '0';
294				end if;
295			end loop;
296			wait;			
297		end process;
298		
299		------------------------------------------------------------
300		-- Clocks 
301		------------------------------------------------------------	
302		
303		p_clk_axi_mem : process
304			constant Frequency_c : real := real(200e6);
305		begin
306			while TbRunning loop
307				wait for 0.5*(1 sec)/Frequency_c;
308				M_Axi_Aclk <= not M_Axi_Aclk;
309			end loop;
310			wait;
311		end process;
312		
313		p_clk_axi_reg : process
314			constant Frequency_c : real := real(166e6);
315		begin
316			while TbRunning loop
317				wait for 0.5*(1 sec)/Frequency_c;
318				S_Axi_Aclk <= not S_Axi_Aclk;
319			end loop;
320			wait;
321		end process;	
322		
323		g_clk_str : for i in 0 to StrCount_c-1 generate
324			p_clk_str : process
325			begin
326				while TbRunning loop
327					wait for 0.5*(1 sec)/(ClkFreq_c(i)+0.1e6);
328					Str_Clk(i) <= not Str_Clk(i);
329				end loop;
330				wait;				
331			end process;
332		end generate;
333			
334		------------------------------------------------------------
335		-- Reg-Access Process
336		------------------------------------------------------------
337		p_regacc  : process
338			variable StartTime_v : time;
339			variable Stream1Armed_v : boolean := false;
340			variable Stream2Armed_v	: boolean := false;
341		begin
342			print("*** Info ***");
343			print("This testbench does not print any status information by default (only errors).");
344			print("To change this behavior, change the constant PrintDefault_c in psi_ms_daq_axi_tb_pkg.");
345		
346			axi_master_init(reg_axi_ms);
347			wait for 1 us;
348			S_Axi_Aresetn <= '1';
349			M_Axi_Aresetn <= '1';
350			
351			-- *** Initial Configuration ***
352			 AxiExpect32(16#0010#, 0, S_Axi_Aclk, reg_axi_ms, reg_axi_sm, "Inital IRQVEC");
353			 AxiWriteAndRead32(16#0014#, 16#000F#, S_Axi_Aclk, reg_axi_ms, reg_axi_sm);
354			 AxiWriteAndRead32(16#0020#, 16#000F#, S_Axi_Aclk, reg_axi_ms, reg_axi_sm);
355			 -- Stream Setup
356			 Str0Setup(S_Axi_Aclk, reg_axi_ms, reg_axi_sm);
357			 Str1Setup(S_Axi_Aclk, reg_axi_ms, reg_axi_sm);
358			 Str2Setup(S_Axi_Aclk, reg_axi_ms, reg_axi_sm); 
359			 Str3Setup(S_Axi_Aclk, reg_axi_ms, reg_axi_sm); 
360			 
361			 -- Enable
362			 AxiWriteAndRead32(16#0000#, 16#0101#, S_Axi_Aclk, reg_axi_ms, reg_axi_sm);
363			 
364			 
365			 -- *** Run Test ***
366			 StartTime_v := now;
367			 while now < StartTime_v+150 us loop
368				wait until rising_edge(S_Axi_Aclk);
369				-- IRQ Handling
370				if Irq = '1' then
371					IrqHandler(S_Axi_Aclk, reg_axi_ms, reg_axi_sm);
372				end if;
373				-- Regular actions
374				Str0Update(S_Axi_Aclk, reg_axi_ms, reg_axi_sm);
375				Str1Update(S_Axi_Aclk, reg_axi_ms, reg_axi_sm);
376				Str2Update(S_Axi_Aclk, reg_axi_ms, reg_axi_sm);
377				Str3Update(S_Axi_Aclk, reg_axi_ms, reg_axi_sm);
378					
379			 end loop;
380			 TbRunning <= false;
381			 
382			 -- *** Check end state ***
383			 assert Str0WinCheck >= 4 report "###ERROR###: Stream 0 checks not completed" severity error;
384			 assert Str1WinCheck = 1 report "###ERROR###: Stream 1 checks not completed" severity error;
385			 assert Str2WinCheck >= 2 report "###ERROR###: Stream 2 checks not completed"  severity error;
386			 assert Str3WinCheck = 2 report "###ERROR###: Stream 3 checks not completed"  severity error;
387			wait;
388		end process;
389		
390		------------------------------------------------------------
391		-- Timestamp Processes
392		------------------------------------------------------------	
393		g_ts : for i in 0 to StrCount_c-1 generate
394			p_ts : process
395			begin
396				while TbRunning loop
397					wait until rising_edge(Str_Clk(0));
398					Timestamp(0) <= std_logic_vector(unsigned(Timestamp(0)) + 1);
399				end loop;
400				wait;
401			end process;
402		end generate;
403		
404		------------------------------------------------------------
405		-- Data Generation Processes
406		------------------------------------------------------------
407		p_str0 : process
408			variable IrqOn : boolean := false;
409		begin
410			wait until rising_edge(Str_Clk(0));
411			while TbRunning loop
412				Str0Sample(Str_Clk(0), Str_Vld(0), Str_Trig(0), Str0_Data);	
413			end loop;
414			wait;
415		end process;
416		
417		p_str1 : process
418		begin
419			Str1Data(Str_Clk(1), Str_Vld(1), Str_Trig(1), Str1_Data);
420			wait;
421		end process;
422		
423		p_str2 : process
424		begin
425			Str2Data(Str_Clk(2), Str_Vld(2), Str_Trig(2), Str2_Data);
426			wait;
427		end process;	
428		
429		p_str3 : process
430		begin
431			Str3Data(Str_Clk(3), Str_Vld(3), Str_Trig(3), Str3_Data);
432			wait;
433		end process;		
434		
435		------------------------------------------------------------
436		-- Check Process
437		------------------------------------------------------------	
438		
439	end;
