226	package body psi_ms_daq_axi_tb_pkg is
227	
228		--------------------------------------------------------
229		-- Helper Procedures
230		--------------------------------------------------------
231		function IntAnd(	int : in integer;
232							op	: in integer) return integer is
233			variable intu, opu : signed(31 downto 0);
234		begin
235			intu := to_signed(int, 32);
236			opu := to_signed(op, 32);
237			return to_integer(intu and opu);
238		end function;
239		
240		procedure print(	str : in string;
241							ena	: in boolean) is
242		begin
243			if ena then
244				print(str);
245			end if;
246		end procedure;
247	
248		--------------------------------------------------------
249		-- Axi Procedures
250		--------------------------------------------------------
251		procedure AxiWrite32(			address		: in	integer;
252										value		: in 	integer;
253								signal	clk			: in	std_logic;
254								signal	ms			: out 	axi_ms_r;
255								signal	sm			: in	axi_sm_r) is
256		begin
257			axi_single_write(address, value, ms, sm, clk);
258		end procedure;
259								
260		procedure AxiRead32(			address		: in	integer;
261										value		: out 	integer;
262								signal	clk			: in	std_logic;
263								signal	ms			: out 	axi_ms_r;
264								signal	sm			: in	axi_sm_r) is
265		begin
266			axi_single_read(address, value, ms, sm, clk);
267		end procedure;
268								
269		procedure AxiExpect32(			address		: in	integer;
270										value		: in 	integer;
271								signal	clk			: in	std_logic;
272								signal	ms			: out 	axi_ms_r;
273								signal	sm			: in	axi_sm_r;
274										msg			: in	string	:= "") is
275		begin
276			axi_single_expect(address, value, ms, sm, clk, msg);
277		end procedure;
278		
279		procedure AxiWriteAndRead32(			address		: in	integer;
280												value		: in 	integer;
281										signal	clk			: in	std_logic;
282										signal	ms			: out	axi_ms_r;
283										signal 	sm			: in	axi_sm_r;
284												msg			: in	string	:= "") is
285		begin
286			axi_single_write(address, value, ms, sm, clk);
287			wait for 400 ns;
288			wait until rising_edge(clk);
289			axi_single_expect(address, value, ms, sm, clk, msg);
290		end procedure;	
291		
292		--------------------------------------------------------
293		-- High Level Procedures
294		--------------------------------------------------------
295		procedure HlCheckMaxLvl(			str			: in	integer;
296											expLevel	: in	integer;
297									signal	clk			: in	std_logic;
298									signal	ms			: out	axi_ms_r;
299									signal 	sm			: in	axi_sm_r) is
300		begin
301			axi_single_expect(REG_CONF_MAXLVLn+REG_CONF_Xn_STEP*str, expLevel, ms, sm, clk, "HlCheckMaxLvl failed");
302		end procedure;
303		
304		procedure HlSetPostTrig(			str			: in	integer;
305											val 		: in	integer;
306									signal	clk			: in	std_logic;
307									signal	ms			: out	axi_ms_r;
308									signal 	sm			: in	axi_sm_r) is
309		begin
310			AxiWriteAndRead32(REG_CONF_POSTTRIGn+REG_CONF_Xn_STEP*str, val, clk, ms, sm, "HlSetPostTrig failed");
311		end procedure;
312		
313		procedure HlSetMode(				str			: in	integer;
314											val 		: in	integer;
315									signal	clk			: in	std_logic;
316									signal	ms			: out	axi_ms_r;
317									signal 	sm			: in	axi_sm_r) is
318		begin
319			axi_single_write(REG_CONF_MODEn+REG_CONF_Xn_STEP*str, val, ms, sm, clk);
320		end procedure;	
321		
322		procedure HlConfStream(				str			: in	integer;
323											bufstart	: in	integer;
324											ringbuf		: in	boolean;
325											overwrite	: in	boolean;
326											wincnt		: in	integer;
327											winsize		: in	integer;
328									signal	clk			: in	std_logic;
329									signal	rqst		: out	axi_ms_r;
330									signal 	rsp			: in	axi_sm_r) is
331			variable v : integer := 0;
332		begin
333			AxiWriteAndRead32(	REG_CTX_REGION+REG_CTX_BUFSTARTn+REG_CTX_Xn_STEP*str, 
334								bufstart, clk, rqst, rsp, "HlConfStream failed BUFSTART");
335			AxiWriteAndRead32(	REG_CTX_REGION+REG_CTX_WINSIZEn+REG_CTX_Xn_STEP*str,
336								winsize, clk, rqst, rsp, "HlConfStream failed WINSIZE");
337			if ringbuf then
338				v := v + VAL_SCFG_RINGBUF;
339			end if;
340			if overwrite then
341				v := v + VAL_SCFG_OVERWRITE;
342			end if;
343			v := v + (2**SFT_SCFG_WINCNT)*(wincnt-1);
344			AxiWriteAndRead32(	REG_CTX_REGION+REG_CTX_SCFGn+REG_CTX_Xn_STEP*str, 
345								v, clk, rqst, rsp, "HlConfStream failed SCFG");
346		end procedure;
347		
348		procedure HlIsRecording(			str			: in	integer;
349									signal	clk			: in	std_logic;
350									signal	ms			: out	axi_ms_r;
351									signal 	sm			: in	axi_sm_r;									
352											val			: out	boolean) is
353			variable v : integer := 0;
354		begin
355			axi_single_read(REG_CONF_REGION+REG_CONF_MODEn+REG_CONF_Xn_STEP*str,
356							v, ms, sm, clk);
357			if IntAnd(v, VAL_MODE_RECORDING) /= 0 then
358				val := true;
359			else
360				val := false;
361			end if;
362		end procedure;
