387									signal 	sm			: in	axi_sm_r;									
388											val			: out	integer) is
389		begin
390			axi_single_read(REG_CONF_REGION+REG_CONF_LASTWINn+REG_CONF_Xn_STEP*str, 
391							val, ms, sm, clk);
392		end procedure;											
393		
394		procedure HlGetCurWin(				str			: in	integer;
395									signal	clk			: in	std_logic;
396									signal	ms			: out	axi_ms_r;
397									signal 	sm			: in	axi_sm_r;									
398											val			: out	integer) is
399			variable v : integer;
400		begin
401			axi_single_read(REG_CTX_REGION+REG_CTX_SCFGn+REG_CTX_Xn_STEP*str, 
402							v, ms, sm, clk);
403			v := IntAnd(v, MSK_SCFG_WINCUR);
404			v := v / (2**SFT_SCFG_WINCUR);
405			val := v;
406		end procedure;	
407		
408		procedure HlGetWinCnt(				str			: in	integer;
409											win			: in	integer;
