416			axi_single_read(REG_WIN_REGION+REG_WIN_WINCNT+REG_WIN_STRn_STEP*str+REG_WIN_WINn_STEP*win, 
417							v, ms, sm, clk);
418			val := IntAnd(v, MSK_WIN_WINCNT_CNT);
419		end procedure;	
420		
421		procedure HlIsTrigWin(				str			: in	integer;
422											win 		: in	integer;
423									signal	clk			: in	std_logic;
424									signal	ms			: out	axi_ms_r;
425									signal 	sm			: in	axi_sm_r;									
426											val			: out	boolean) is
427			variable v : integer;
428		begin
429			axi_single_read(REG_WIN_REGION+REG_WIN_WINCNT+REG_WIN_STRn_STEP*str+REG_WIN_WINn_STEP*win, 
430							v, ms, sm, clk);
431			val := v < 0;		
432		end procedure;
