435											win			: in	integer;
436									signal	clk			: in	std_logic;
437									signal	ms			: out	axi_ms_r;
438									signal 	sm			: in	axi_sm_r) is
439			variable v : integer;
440		begin
441			axi_single_write(REG_WIN_REGION+REG_WIN_WINCNT+REG_WIN_STRn_STEP*str+REG_WIN_WINn_STEP*win, 
442								0, ms, sm, clk);
