1	------------------------------------------------------------------------------
2	--  Copyright (c) 2019 by Paul Scherrer Institute, Switzerland
3	--  All rights reserved.
4	--  Authors: Oliver Bruendler
5	------------------------------------------------------------------------------
6	
7	------------------------------------------------------------
8	-- Description
9	------------------------------------------------------------
10	-- Stream 0 works in ringbuffer mode (without overwrite). It 
11	-- produces 8-bit data (modulo counter). IRQs are located at samples
12	-- containing data 30, 60 and 90. IRQs are suppressed until 15 us after
13	-- simulation to see if IRQ enable works correctly.
14	-- The IRQ handler also sets the window sample counter to zero to ensure
15	-- more data can be recorded after the IRQ.
16	
17	------------------------------------------------------------
18	-- Libraries
19	------------------------------------------------------------
20	library ieee;
21		use ieee.std_logic_1164.all;
22		use ieee.numeric_std.all;
23	
24	library work;
25		use work.psi_common_math_pkg.all;
26		use work.psi_common_array_pkg.all;
27		use work.psi_ms_daq_pkg.all;
28	
29	library work;
30		use work.psi_tb_txt_util.all;
31		use work.psi_tb_compare_pkg.all;
32		use work.psi_ms_daq_axi_tb_pkg.all;
33		use work.psi_tb_axi_pkg.all;
34	
35	------------------------------------------------------------
36	-- Package Header
37	------------------------------------------------------------
38	package psi_ms_daq_axi_tb_str0_pkg is
39	
40		constant PrintStr0_c			: boolean	:= PrintDefault_c;
41	
42		-- Memory
43		constant Str0BufStart_c			: integer	:= 16#1000#;
44		constant Str0WinSize_c			: integer	:= 100;
45		constant Str0Windows_c			: integer	:= 3;
46		alias Memory0 : t_aslv8(0 to Str0WinSize_c*Str0Windows_c) is Memory(Str0BufStart_c to Str0BufStart_c+Str0WinSize_c*Str0Windows_c);
47		
48		--------------------------------------------------------
49		-- Persistent State
50		--------------------------------------------------------
51		shared variable Str0NextWin 	: integer := 0;
52		shared variable Str0WinCheck 	: integer := 0;
53		shared variable Str0LastTs 		: integer;	
54		shared variable Str0IrqOn 		: boolean := false;
55		shared variable Str0Disabled	: boolean := false;
56	
57		--------------------------------------------------------
58		-- Data Generation
59		--------------------------------------------------------
60		procedure Str0Sample(	signal clk	: in	std_logic;
61								signal vld	: out	std_logic;
62								signal trig	: out	std_logic;
63								signal data : out	std_logic_vector(7 downto 0));
64								
65		--------------------------------------------------------
66		-- IRQ Handler
67		--------------------------------------------------------
68		procedure Str0Handler(	signal	clk			: in	std_logic;
69								signal	rqst		: out 	axi_ms_r;
70								signal	rsp			: in	axi_sm_r);	
71	
72		--------------------------------------------------------
73		-- Setup
74		--------------------------------------------------------
75		procedure Str0Setup(	signal clk			: in	std_logic;
76								signal rqst			: out	axi_ms_r;
77								signal rsp			: in	axi_sm_r);
78	
79		--------------------------------------------------------
80		-- Update
81		--------------------------------------------------------
82		procedure Str0Update(	signal clk			: in	std_logic;
83								signal rqst			: out	axi_ms_r;
84								signal rsp			: in	axi_sm_r);							
85								
86								
87	end package;
88	
89	------------------------------------------------------------
90	-- Package Body
91	------------------------------------------------------------
92	package body psi_ms_daq_axi_tb_str0_pkg is
93	
94		--------------------------------------------------------
95		-- Data Generation
96		--------------------------------------------------------
97		procedure Str0Sample(	signal clk	: in	std_logic;
98								signal vld	: out	std_logic;
99								signal trig	: out	std_logic;
100								signal data : out	std_logic_vector(7 downto 0)) is
101		begin
102			vld <= '1';
103			if (now > 15 us) and (to_integer(unsigned(data)) = 0) then	
104				Str0IrqOn := true;
105			end if;
106			case to_integer(unsigned(data)) is
107				when 30 | 60 | 90 => 	
108					if Str0IrqOn then
109						trig <= '1';
110					end if;
111				when others => null;
112			end case;
113			wait until rising_edge(clk);
114			vld <= '0';
115			trig <= '0';
116			data <= std_logic_vector(unsigned(data)+1);
117			wait until rising_edge(clk);
118		end procedure;
119	
120		--------------------------------------------------------
121		-- IRQ Handler
122		--------------------------------------------------------
123		procedure Str0Handler(	signal	clk			: in	std_logic;
124								signal	rqst		: out 	axi_ms_r;
125								signal	rsp			: in	axi_sm_r) is
126			variable v : integer;
127			variable curwin : integer;
128			variable lastwin : integer;
129			variable wincnt : integer;
130			variable winstart, winend : integer;
131			variable winlast : integer;
132			variable addr : integer;
133			variable tslo : integer;
134			variable firstLoop : boolean := true;
135			variable HasTrigger : boolean;
136		begin	
137			print("------------ Stream 0 Handler ------------", PrintStr0_c);
138			HlGetMaxLvl(0, clk, rqst, rsp, v);
139			print("MAXLVL: " & to_string(v), PrintStr0_c);
140			HlGetCurWin(0, clk, rqst, rsp, curwin);
141			print("CURWIN: " & to_string(curwin), PrintStr0_c);
142			HlGetLastWin(0, clk, rqst, rsp, lastwin);
143			print("LASTWIN: " & to_string(lastwin), PrintStr0_c);
144			print("", PrintStr0_c);
145			if Str0Disabled then
146				print("Skipped, stream disabled", PrintStr0_c);
147				print("", PrintStr0_c);
148			else
149				HlIsTrigWin(0, Str0NextWin, clk, rqst, rsp, HasTrigger);
150				-- lastwin = nextwin can occur if al lwindows are filled. In all cases we only interpret windows containing triggers.
151				while ((Str0NextWin /= ((lastwin+1) mod 3)) or firstLoop) and HasTrigger loop
152					firstLoop := false;
153					print("*** Window " & to_string(Str0NextWin) & " / Number: " & to_string(Str0WinCheck) & " ***", PrintStr0_c);	
154					HlGetWinCnt(0, Str0NextWin, clk, rqst, rsp, wincnt);
155					print("WINCNT: " & to_string(wincnt), PrintStr0_c);
156					HlClrWinCnt(0, Str0NextWin, clk, rqst, rsp);
157					HlGetWinLast(0, Str0NextWin, clk, rqst, rsp, winlast);
158					print("WINLAST: " & to_string(winlast), PrintStr0_c);	
159					HlGetTsLo(0, Str0NextWin, clk, rqst, rsp, tslo);
160					print("WINTSLO: " & to_string(tslo), PrintStr0_c);	
161					HlGetTsHi(0, Str0NextWin, clk, rqst, rsp, v);
162					print("WINTSHI: " & to_string(v), PrintStr0_c);	
163					winstart := Str0BufStart_c + Str0NextWin*Str0WinSize_c;
164					winend := winstart + Str0WinSize_c - 1;
165					case Str0WinCheck is
166						when 0 => 
167							-- Windows full because dat received for quite some time
168							IntCompare(Str0WinSize_c, wincnt, "Stream0: WINCNT wrong");
169							-- Check Values
170							addr := winlast;
171	
172							for i in 256+30+3-99 to 256+30+3 loop
173								if addr = winend then
174									addr := winstart;
175								else
176									addr := addr + 1;
177								end if;
178								StdlvCompareInt (i mod 256, Memory(addr), "Stream0: Wrong value at 0x" & to_hstring(to_unsigned(addr,32)), false);
179							end loop;						
180	
181						when 1 => 
182							-- Trigger following each other with 30 samples difference
183							IntCompare(30, wincnt, "Stream0: WINCNT wrong");
184							IntCompare(30*2, tslo-Str0LastTs, "Stream0: TS difference wrong");
185							-- Check Values
186							addr := winstart;
187							for i in 34 to 63 loop
188								StdlvCompareInt (i, Memory(addr), "Stream0: Wrong value", false);
189								addr := addr + 1; -- does never wrap
190							end loop;	
191							
192						when 2 => 
193							-- Trigger following each other with 30 samples difference
194							IntCompare(30, wincnt, "Stream0: WINCNT wrong");	
195							IntCompare(30*2, tslo-Str0LastTs, "Stream0: TS difference wrong");					
196							-- Check Values
197							addr := winstart;
198							for i in 64 to 93 loop
199								StdlvCompareInt (i, Memory(addr), "Stream0: Wrong value", false);
200								addr := addr + 1; -- does never wrap
201							end loop;						
202						when 3 => 
203							-- Full buffer recorded after emptying first buffer
204							IntCompare(100, wincnt, "Stream0: WINCNT wrong");
205							IntCompare((256-2*30)*2, tslo-Str0LastTs, "Stream0: TS difference wrong");
206							-- Disable stream IRQ				
207							AxiRead32(REG_CONF_IRQENA_ADDR, v, clk, rqst, rsp);
208							v := IntAnd(v, 16#0FE#);
209							AxiWrite32(REG_CONF_IRQENA_ADDR, v, clk, rqst, rsp);
210							AxiRead32(REG_CONF_STRENA_ADDR, v, clk, rqst, rsp);
211							v := IntAnd(v, 16#0FE#);
212							AxiWrite32(REG_CONF_STRENA_ADDR, v, clk, rqst, rsp);
213							Str0Disabled := true;					
214							-- Check Values
215							addr := winlast + 1;
216							for i in 256+30+3-99 to 256+30+3 loop
217								StdlvCompareInt (i mod 256, Memory(addr), "Stream0: Wrong value", false);
218								if addr = winend then
219									addr := winstart;
220								else
221									addr := addr + 1;
222								end if;
223							end loop;	
224							
225						when others => null;
226					end case;
227					print("", PrintStr0_c);
228					Str0LastTs := tslo;
229					Str0NextWin := (Str0NextWin + 1) mod 3;
230					Str0WinCheck := Str0WinCheck + 1;
231				end loop;
232			end if;
233		end procedure;
234			
235		--------------------------------------------------------
236		-- Setup
237		--------------------------------------------------------
238		procedure Str0Setup(	signal clk			: in	std_logic;
239								signal rqst			: out	axi_ms_r;
240								signal rsp			: in	axi_sm_r) is
241		begin
242			HlCheckMaxLvl(0, 0, clk, rqst, rsp);
243			HlSetPostTrig(0, 3, clk, rqst, rsp);
244			HlSetMode(0, VAL_MODE_RECM_CONT, clk, rqst, rsp);
245			HlConfStream(	str => 0, bufstart => Str0BufStart_c, ringbuf => true, overwrite => false, wincnt => Str0Windows_c, winsize => Str0WinSize_c, 
