244		------------------------------------------------------------
245		-- Emulate Memory
246		------------------------------------------------------------	
247		p_mem : process
248			variable Address_v		: integer;
249			variable Size_v			: integer;
250		begin
251			axi_slave_init(axi_sm);
252			wait until rising_edge(M_Axi_Aclk);
