			S_Axi_Aresetn				=> S_Axi_Aresetn,
			S_Axi_ArId					=> reg_axi_ms.arid,
			S_Axi_ArAddr				=> reg_axi_ms.araddr,
			S_Axi_Arlen					=> reg_axi_ms.arlen,
