			S_Axi_ArReady				=> reg_axi_sm.arready,
			S_Axi_RId					=> reg_axi_sm.rid,
			S_Axi_RData					=> reg_axi_sm.rdata,
			S_Axi_RResp					=> reg_axi_sm.rresp,
