142			-- Calculate window to read
143			if curwin = 0 then
144				curwin := Str2Windows_c-1;
145			else
146				curwin := curwin-1;
147			end if;
148			-- Read window data		
149			-- Check if recording is finished
150			HlIsTrigWin(2, curwin, clk, rqst, rsp, isTrig);
151			-- Check if window is fully written to memory
152			HlGetLastWin(2, clk, rqst, rsp, lastwin);
153			-- Execute
154			if not isTrig then
155				print("Skipped: not a trigger window", PrintStr2_c);
156			elsif curwin /= lastwin then
157				print("Skipped: not written to memory yet " & str(curwin) & " " & str(lastwin), PrintStr2_c);
