191			HlSetPostTrig(2, Str2PostTrig_c, clk, rqst, rsp);
192			HlSetMode(2, VAL_MODE_RECM_SINGLE, clk, rqst, rsp);
193			HlConfStream(	str => 2, bufstart => Str2BufStart_c, ringbuf => false, overwrite => true, wincnt => Str2Windows_c, winsize => Str2WinSize_c, 
194							clk => clk, rqst => rqst, rsp => rsp);
195		end procedure;
