205			if ((Str2FrameCnt = 2) or (Str2FrameCnt = 12)) and 
206				(Str2SplCnt >= 80) and (Str2SplCnt <= 150) and not Stream2Armed_v then
207				Stream2Armed_v := true;
208				HlSetMode(2, VAL_MODE_RECM_SINGLE + VAL_MODE_ARM, clk, rqst, rsp);
209				Str2ExpFrame := Str2FrameCnt + 1;
